class Solution(object):
    def clumsy(self, n):
        ops = ['*', '/', '+', '-'] * (n // 4 + 1)
        stack = [n]
        num = n - 1
        for i, op in enumerate(ops):
            if num <= 0:
                break
            if op == '*':
                stack.append(stack.pop() * num)
            elif op == '/':
                stack.append(int(stack.pop() / num))
            elif op == '+':
                stack.append(num)
            else:  # op == '-'
                stack.append(-num)
            num -= 1
        return sum(stack)
